import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../core/providers.dart';
import '../../repositories/providers.dart';

class ProfileScreen extends ConsumerWidget { const ProfileScreen({super.key}); @override Widget build(BuildContext context, WidgetRef ref) { final user = ref.watch(authProvider).currentUser; return Scaffold(appBar: AppBar(title: const Text('Profil')), body: ListView(padding: const EdgeInsets.all(16), children: [CircleAvatar(radius: 48, backgroundImage: user?.photoURL == null ? null : NetworkImage(user!.photoURL!), child: user?.photoURL == null ? const Icon(Icons.person, size: 48) : null), const SizedBox(height: 16), Center(child: Text(user?.displayName ?? 'User PadelFinder', style: Theme.of(context).textTheme.titleLarge)), Center(child: Text(user?.email ?? '')), const SizedBox(height: 24), const Card(child: ListTile(leading: Icon(Icons.analytics_outlined), title: Text('Statistik profil'), subtitle: Text('Total postingan, komentar, dan favorit dihitung realtime melalui Firestore.'))), ListTile(leading: const Icon(Icons.edit), title: const Text('Edit Profil'), onTap: () {}), ListTile(leading: const Icon(Icons.lock), title: const Text('Ubah Password'), onTap: () { if (user?.email != null) ref.read(authRepositoryProvider).resetPassword(user!.email!); }), ListTile(leading: const Icon(Icons.logout), title: const Text('Logout'), onTap: () => ref.read(authRepositoryProvider).logout())])); }}
